script:
// Parent Doctype
frappe.ui.form.on("Practitioner Schedule", {
    before_save(frm) {
        generate_tokens(frm);
    },
    refresh(frm) {
        generate_tokens(frm);
    }
});


// 🔹 Child Table Doctype (IMPORTANT: replace with your actual child table name)
frappe.ui.form.on("Practitioner Schedule Time Slots", {
    
    // When row is added
    time_slots_add(frm) {
        generate_tokens(frm);
    },

    // When fields are changed
    from_time(frm, cdt, cdn) {
        generate_tokens(frm);
    },

    to_time(frm, cdt, cdn) {
        generate_tokens(frm);
    },

    day(frm, cdt, cdn) {
        generate_tokens(frm);
    },

    // When row is removed
    time_slots_remove(frm) {
        generate_tokens(frm);
    }
});


// 🔹 Helper: Convert time → minutes
function time_to_minutes(time) {
    if (!time) return 0;

    let parts = time.split(":").map(Number);
    return (parts[0] * 60) + parts[1];
}


// 🔹 Main Function
function generate_tokens(frm) {
    if (!frm.doc.time_slots || frm.doc.time_slots.length === 0) return;

    // Clone and sort rows (Day → From Time)
    let rows = [...frm.doc.time_slots].sort((a, b) => {

        if ((a.day || '') !== (b.day || '')) {
            return (a.day || '').localeCompare(b.day || '');
        }

        return time_to_minutes(a.from_time) - time_to_minutes(b.from_time);
    });

    let current_day = null;
    let token_counter = 0;

    rows.forEach(row => {

        // Reset counter when day changes
        if (row.day !== current_day) {
            current_day = row.day;
            token_counter = 1;
        } else {
            token_counter++;
        }

        let token = `Token ${token_counter}`;

        // Set value in child table
        frappe.model.set_value(
            row.doctype,
            row.name,
            "custom_token_no",
            token
        );
    });

    // Refresh child table UI
    frm.refresh_field("time_slots");
}

frappe.ui.form.on("Patient Appointment", { 
    validate(frm) {
        regenerate_token(frm);
    }
});

function regenerate_token(frm) {

    if (frm.doc.appointment_for !== "Practitioner") return;

    if (!frm.doc.practitioner || !frm.doc.appointment_date || !frm.doc.appointment_time) {
        return;
    }

    // Clear before regenerating
    frm.set_value("custom_token_no", null);

    frappe.call({
        method: "someshwara_hospital.api.token_api.get_token_for_appointment",
        args: {
            practitioner: frm.doc.practitioner,
            appointment_date: frm.doc.appointment_date,
            appointment_time: frm.doc.appointment_time
        },
        callback: function (r) {
            if (r.message) {
                frm.set_value("custom_token_no", r.message);
            }
        }
    });
}
